      "mainEntity": [
        {
          "@type": "Question",
          "name": "Which deductions appear in a marketplace settlement report?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "A settlement report deducts commission, closing fee, fixed fee, shipping or weight-handling charges, advertising and promotion costs, return and RTO charges, GST on those fees, GST TCS and TDS from the gross order value. On a Rs 1,000 order the seller may receive around Rs 720 after these deductions, which is why payouts never equal invoice value."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between marketplace settlement reconciliation and bank reconciliation?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Bank reconciliation matches the cash book to the bank statement, a two-way tie. Marketplace settlement reconciliation is three-way: the sales or order register, the settlement report from the platform, and the credit received in the bank. A payout can agree with the bank yet still hide wrong commission or a missing return credit that only the three-way match exposes."
          }
        },
        {
          "@type": "Question",
          "name": "Where does GST TCS appear in a marketplace settlement statement?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "GST TCS shows as a separate deduction of 0.5 per cent of the net taxable value of goods supplied, made up of 0.25 per cent CGST and 0.25 per cent SGST, or 0.5 per cent IGST on inter-state sales. It reaches the electronic cash ledger only after the operator files GSTR-8, and is accepted by the seller from the TCS credit tab."
          }
        }
      ]
